// Produces a stable date window the whole workflow can reference.
const horizonDays = 180;
const now = new Date();
const todayISO = now.toISOString().slice(0,10);
const horizon = new Date(now.getTime() + horizonDays*24*3600*1000).toISOString().slice(0,10);
return [{ json: { todayISO, horizon, horizonDays } }];

// Parse AI output into a single item: { events: [...] }
function stripFences(s) {
  return String(s || "")
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}
function parsePossiblyDoubleEncoded(raw) {
  if (raw == null) return null;
  if (typeof raw === "object") return raw;
  const cleaned = stripFences(String(raw));
  let p;
  try { p = JSON.parse(cleaned); } catch { return null; }
  if (typeof p === "string") {
    try { p = JSON.parse(p); } catch { return null; }
  }
  return p;
}
const raw = $json.output ?? $json.text ?? $json.response ?? "";
const parsed = parsePossiblyDoubleEncoded(raw);
if (!parsed || !Array.isArray(parsed.events)) {
  throw new Error("No valid events[] found in AI output.");
}
return [{ json: { events: parsed.events } }];

// Normalize + enforce upcoming window + FK-safe primary_sector.
// IMPORTANT: Run once for each item (this node is placed after Split Out Events).
function norm(s) { return String(s ?? "").replace(/\s+/g, " ").trim(); }
function toDate(s) { const d = new Date(String(s ?? "")); return isNaN(d.getTime()) ? null : d; }

const todayISO = $node["Set Date Window"].json.todayISO;
const horizonISO = $node["Set Date Window"].json.horizon;

const title = norm($json.title);
const location = norm($json.location);
const event_url = norm($json.event_url);
const source_url = norm($json.source_url || $json.event_url) || null;

const start = toDate($json.event_date);
if (!title || !location || !event_url || !start) return [];

// Drop generic listing pages (quick heuristic)
if (/\/events\/?$/.test(event_url)) return [];

const startYMD = start.toISOString().slice(0,10);
if (startYMD < todayISO) return [];
if (startYMD > horizonISO) return [];

// FK-safe sector
const allowed = new Set(["housing","infrastructure","urban-resilience","disaster-risk"]);
let sector = norm($json.primary_sector).toLowerCase();
if (sector === "urban resilience") sector = "urban-resilience";
if (sector === "disaster risk") sector = "disaster-risk";
if (!allowed.has(sector)) sector = "infrastructure";

// Ensure NOT NULL event_type
const event_type = norm($json.event_type) || "other";

return [{
  json: {
    // events table payload (source_id intentionally omitted; use DB default)
    title_uk: title,
    title_en: null,
    title_de: null,
    description_uk: norm($json.description_uk || $json.description || "") || null,
    description_en: null,
    description_de: null,
    event_date: start.toISOString(),
    event_end_date: toDate($json.event_end_date)?.toISOString() || null,
    location,
    location_type: norm($json.location_type) || null,
    event_url,
    primary_sector: sector,
    secondary_sectors: Array.isArray($json.secondary_sectors) ? $json.secondary_sectors : [],
    event_type,
    organizer_stakeholder_id: $json.organizer_stakeholder_id ?? null,
    organizer_name: norm($json.organizer_name) || null,
    source_url,
    credibility_tier: Number.isFinite($json.credibility_tier) ? $json.credibility_tier : 2,
    original_language: norm($json.original_language) || "en",
    translation_status: "machine",
    llm_extracted_speakers: Array.isArray($json.llm_extracted_speakers) ? $json.llm_extracted_speakers : [],
    llm_topics: Array.isArray($json.llm_topics) ? $json.llm_topics : [],
    llm_expected_attendees: norm($json.llm_expected_attendees) || null
  }
}];
